```

---

### Alternative — sequential reads (simpler, slower for many files)

If you want to keep the original loop style, use `for...of` so each `await` actually pauses the loop:

```js
const fs = require('fs/promises');

async function main(files) {
  let total = 0;
  for (const f of files) {
    const data = await fs.readFile(f, 'utf8');
    total += data.length;
  }
  console.log('total:', total);
  return total;
}

(async () => {
  try {
    await main(['file1.txt', 'file2.txt', 'file3.txt']);
  } catch (err) {
    console.error('Error reading files:', err);
    process.exit(1);
  }
})();
```

Both versions guarantee that `console.log` runs only after all files have been processed. Use the **parallel version** if file I/O is the bottleneck and the order of reads does not matter; use the **sequential version** if you need predictable order or lower memory/IO pressure.
